import { useState } from "react";

export default function GitHubFinder() {
  // Наші три кити мережевих запитів
  const [username, setUsername] = useState("");
  const [userData, setUserData] = useState(null); // Тут буде об'єкт з даними
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState(null);

  // Не забудь слово async!
  async function fetchUser(e) {
    e.preventDefault();
    if (!username.trim()) return;

    // 1. Перед початком запиту скидаємо старі помилки і вмикаємо спінер
    setError(null);
    setIsLoading(true);
    setUserData(null);

    try {
      // 2. ТУТ ТВІЙ КОД: Зроби запит через fetch до "https://api.github.com/users/" + username
      // Не забудь про await!
      // const response = ...

      // Перевіряємо, чи сервер не відповів помилкою 404
      if (!response.ok) {
        throw new Error("Користувача не знайдено ❌");
      }

      // 3. ТУТ ТВІЙ КОД: Розпакуй відповідь у JSON
      // const data = ...

      // 4. ТУТ ТВІЙ КОД: Збережи отримані data у стан userData


    } catch (err) {
      // Якщо інтернет впав або сервер відповів 404, ми потрапляємо сюди
      setError(err.message);
    } finally {
      // Цей блок виконується ЗАВЖДИ в кінці, незалежно від успіху чи помилки
      setIsLoading(false);
    }
  }

  return (
    <div style={{ background: "#1e1e2e", color: "#cdd6f4", padding: "40px", minHeight: "100vh", fontFamily: "monospace" }}>
      <h2>$ github-fetcher</h2>

      <form onSubmit={fetchUser} style={{ marginBottom: "20px", display: "flex", gap: "10px" }}>
        <input 
          type="text" 
          placeholder="Введіть нікнейм (напр. torvalds)"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          style={{ padding: "10px", background: "#313244", color: "#cdd6f4", border: "none", borderRadius: "5px" }}
        />
        <button type="submit" disabled={isLoading} style={{ padding: "10px 20px", background: "#89b4fa", color: "#1e1e2e", border: "none", borderRadius: "5px", cursor: "pointer" }}>
          {isLoading ? "Шукаю..." : "Знайти"}
        </button>
      </form>

      {/* УМОВНИЙ РЕНДЕРИНГ: Малюємо різні блоки залежно від стану */}

      {isLoading && <p style={{ color: "#f9e2af" }}>Завантаження даних з сервера...</p>}

      {error && <p style={{ color: "#f38ba8" }}>Помилка: {error}</p>}

      {/* Якщо є дані і немає завантаження - малюємо картку */}
      {userData && !isLoading && (
        <div style={{ background: "#313244", padding: "20px", borderRadius: "8px", maxWidth: "300px" }}>
          <img src={userData.avatar_url} alt="Avatar" style={{ width: "100px", borderRadius: "50%" }} />
          <h3>{userData.name || userData.login}</h3>
          <p>{userData.bio || "Біографія відсутня"}</p>
          <p>📁 Публічні репозиторії: {userData.public_repos}</p>
        </div>
      )}

    </div>
  );
}
